import{_ as e,o,c as i,ag as l}from"./chunks/framework-C5-Jzrz4.js";const a=JSON.parse('{"title":"JsonViewer JSON 查看器","description":"@vben/common-ui 的 JSON 树形查看器，支持 bigint、安全解析和交互事件","frontmatter":{"title":"JsonViewer JSON 查看器","description":"@vben/common-ui 的 JSON 树形查看器，支持 bigint、安全解析和交互事件","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/json-viewer.md","filePath":"scripts/components/common-ui/json-viewer.md","lastUpdated":null}');const c=e({name:"scripts/components/common-ui/json-viewer.md"},[["render",function(e,a,c,d,r,n){return o(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="jsonviewer" tabindex="-1"><code>JsonViewer</code> <a class="header-anchor" href="#jsonviewer" aria-label="Permalink to &quot;`JsonViewer`&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>JsonViewer</code> 是项目中的交互式 JSON 查看器，基于 <code>vue-json-viewer</code> 做了 bigint 兼容、文案本地化和事件包装。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>结构化配置查看</li><li>调试接口响应</li><li>需要对 JSON 节点做点击回调的场景</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/effects/common-ui/src/components/json-viewer/index.ts</code></li><li><code>packages/effects/common-ui/src/components/json-viewer/index.vue</code></li><li><code>packages/effects/common-ui/src/components/json-viewer/types.ts</code></li><li><code>packages/effects/common-ui/src/components/json-viewer/style.scss</code></li></ul><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><ul><li><code>JsonViewer</code></li><li><code>JsonViewerProps</code></li><li><code>JsonViewerAction</code></li><li><code>JsonViewerValue</code></li><li><code>JsonViewerToggle</code></li></ul><h3 id="关键-props" tabindex="-1">关键 Props <a class="header-anchor" href="#关键-props" aria-label="Permalink to &quot;关键 Props&quot;">​</a></h3><ul><li><code>value</code></li><li><code>expandDepth</code></li><li><code>copyable</code></li><li><code>sort</code></li><li><code>boxed</code></li><li><code>theme</code></li><li><code>expanded</code></li><li><code>timeformat</code></li><li><code>previewMode</code></li><li><code>showArrayIndex</code></li><li><code>showDoubleQuotes</code></li></ul><h3 id="事件" tabindex="-1">事件 <a class="header-anchor" href="#事件" aria-label="Permalink to &quot;事件&quot;">​</a></h3><ul><li><code>click</code></li><li><code>copied</code></li><li><code>keyClick</code></li><li><code>toggle</code></li><li><code>valueClick</code></li></ul><h3 id="实现特点" tabindex="-1">实现特点 <a class="header-anchor" href="#实现特点" aria-label="Permalink to &quot;实现特点&quot;">​</a></h3><ul><li>如果 <code>value</code> 是字符串，会先做 JSON 解析。</li><li>解析过程使用 <code>json-bigint</code>，用于兼容大整数。</li><li><code>copyable</code> 既可以是布尔值，也可以是复制文案配置对象。</li><li>点击 JSON 节点时，组件会尽量还原路径、层级和值信息。</li></ul><h2 id="使用方式与注意事项" tabindex="-1">使用方式与注意事项 <a class="header-anchor" href="#使用方式与注意事项" aria-label="Permalink to &quot;使用方式与注意事项&quot;">​</a></h2><ul><li>如果传入的是非法 JSON 字符串，组件会回退为空对象。</li><li>当前实现依赖 <code>vue-json-viewer</code> 的内部结构，样式和交互不适合随意魔改。</li></ul>',18)])])}]]);export{a as __pageData,c as default};
